head.script:
/**
 * 화 면 명 : 하역노임실적등록
 * 메뉴경로 : 물류/작업실적/노임/
 * ASIS경로 : /debis/dongwon-debis-engine/src/main/webapp/ds/op/wrkrslts/wagewrkrslts/op_307_01_01b.jsp
 * 작 성 자 : 배기원
 * 작 업 일 : 2026-01-27
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 * 참고사항
 *    1. login정보 확인 필요 
 *     ☞  $c.data.getMemInfo() 처리
 *    2. op_307_01_18p.xml, op_307_01_03p.xml 팝업 확인 필요
 *    3. ☏ asis의 dataSet.UseFilter = true 이고 dataSet.filter()를 호출해야 event=OnFilter(row) 이벤트가 탐(중요)
 *    4. TOBE ds_retrieveResult2.setRowPosition(0, event);     이벤트 안탐 scwin.ds_retrieveResult2_onrowpositionchange
 *            gr_retrieveResult2.setFocusedCell(0, 0, false);  이벤트 탐   scwin.ds_retrieveResult2_onrowpositionchange
 *    5. gr_retrieveResult2[하역물량실적]의 반 컬럼 2개로 처리 : scwin.f_checkLunionInfo 메소드에서 사용
 *     ☞ lunionOrgCd[textImage](asis : 'EditStyle'='Popup') , lunionOrgCd2[select](asis : 'EditStyle'='Lookup')
 *    6. 로딩 후 처음 조회 시 gr_retrieveResult3[항증코드] 그리드 filter 처리안함(그 후부터 scwin.rFlag = 0으로 되서 처리됨)
 *     ☞ 처음부터 filter 처리하는 방법 : scwin.setInit()의 // scwin.rFlag = 1; 주석해제
 *     ☞ 문의 후 ASIS 오류로 확인(scwin.rFlag = 0으로 하면 필터, 1로하면 ASIS와 같이되도록 로직 수정함)
 *    7. "hiddenVisible":true 되어 있는 항목 일단 false 처리[hiddenCol="true" => hiddenCol="false"]
 *      TODO : 단 반[lunionOrgCd2]만 hiddenCol="true"(asis에는 없고 tobe로직 때문에 추가한 컬럼임)
 * 테스트데이터 
 *    1. 본선관리번호[A0605001], 수출입구분[수입], 작업방법[일반], 작업일자[20260524], SHIFT[전체]
 *     ☞ asis는 처음로드 후 할증코드에 데이터 나오는데 다음에 조회시는 안나옴
 *        tobe 처음로드 후 조회 시에도 할증코드 안나오도록 처리됨
 *    2. 고객지원(반장, 반장외인원수보임) : 본선관리번호[D2501369], 수출입구분[수입], 작업일자[20250117], 구분[컨테이너]
 *    3. 본선관리번호[D2002463]
 *    4. 고객지원 : 본선관리번호[H2501011], 작업일자[20250120]
 * 수정이력 :
 *    - 2026-01-27      배기원    최초작성
 */
scwin.today           = ""; //현재일자

//로그인 정보(이 화면에서는 사용안함)
scwin.memJson;

scwin.rFlag           = 0;  //ASIS와 같은 결과나올려고 처리한것임[0:필터, 1:최초조회 시만 필터]
scwin.retrieve2       = 0;  //TOBE 사용안함(따로 서브미션을 줘서 flag 의미가 없음)
scwin.pos_groupCode   = 0;
scwin.booleanMsg      = false;
scwin.isChecked       = false;
scwin.lobranCd        = "";
scwin.autoLoadType    = 0;
scwin.autoLoadPostCnt = 0;
scwin.isAgreementVolumeFilterClear = false;
scwin.cntLUnion       = 1;

//TOBE 추가
scwin.ds_retrieveResult3_UseFilter        = false;
scwin.ds_retrieveResult4_UseFilter        = false;
scwin.ds_agreementVolumeResults_UseFilter = false;

scwin.f_commCdPopupRow = 0;     //그리드 팝업 호출 시 ROW값
scwin.oldValue = "";

/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
    // var vWrkPlNm = ds_retrieveResult1.getCellData(1, "wrkPlNm");

    // var dsHeader = "cvsslMgntNo:STRING(8)," +
    //     "impExpClsCd:STRING(1)," +
    //     "wrkDt:STRING(8)," +
    //     "wrkMthdCd:STRING(2)," +
    //     "shiftClsCd:STRING(1), " +
    //     "lunionOrgCd";

    // ds_condition.SetDataHeader(dsHeader);
    // ds_condition.insertRow();

    // var dsHeader2 = "selpchItemCd:STRING(4)," +
    //     "scDtlSeqNo:DECIMAL(5)," +
    //     "scName:STRING(100)";

    // ds_scName.SetDataHeader(dsHeader2);

    // var dsHeader3 = "selpchItemCd:STRING(4)," +
    //     "scDtlSeqNo:DECIMAL(5)," +
    //     "scName:STRING(100)";

    // ds_scName3.SetDataHeader(dsHeader3);

    // var ds_agreedVolumeHeader = "cvsslMgntNo:STRING"
    //     + ",expimpClsCd:STRING"
    //     + ",isModifyOnly:STRING";

    // ds_agreedVolumeCondition.SetDataHeader(ds_agreedVolumeHeader);

    // var ds_condition_delete_Header = "odrNo:STRING"
    //     + ",wrkDt:STRING"
    //     + ",shiftClsCd:STRING"
    //     ;
    // ds_condition_delete.SetDataHeader(ds_condition_delete_Header);
    // ds_condition_delete.insertRow();

    // acb_expClsCd.index = 0;
    // acb_shiftCd.index = 0;
    // ica_wrkDt.setValue = "scwin.toDay";

    // $c.gus.cfDisableBtnOnly([btn_add, btn_addRow, btn_deleteRow, btn_cancelRow, btn_autoLoad, btn_openUnionPopUp, btn_delete, btn_cancel, btn_allDeleteRow, btn_allCancelRow]); //
    // ed_cntLUnion.readOnly = true;
};


/**
 * 초기세팅(TOBE 그리드, 총건수)
 */
scwin.setInit = function() {
    gr_retrieveResult2.setNoResultMessageVisible(false);
    gr_retrieveResult3.setNoResultMessageVisible(false);
    ds_retrieveResult1.removeAll();
    ds_retrieveResult2.removeAll();
    ds_retrieveResult3.removeAll();
    ds_retrieveResult4.removeAll();
    ds_retrieveResult5.removeAll();
    ds_agreementVolumeSaveResults.removeAll();
    ds_orderInfo.removeAll();
    ds_wrkIndictNo.removeAll();
    totalRows1.setValue("0");
    totalRows2.setValue("0");

    //하역노역실적 그리드 hidden
    gr_retrieveResult2.setColumnVisible("lunionOrgCd"   , true);         //반(textImage)
    gr_retrieveResult2.setColumnVisible("lunionOrgCd2"  , false);        //반(select)
    gr_retrieveResult2.setColumnVisible("chiefNm"       , false);        //반장
    gr_retrieveResult2.setColumnVisible('chiefExceptStaffCnt', false);   //반장외;인원수
    gr_retrieveResult2.setColumnVisible("agrVolmgntNo"  , false);        //협정물량; 관리번호

    scwin.ds_retrieveResult3_UseFilter        = false;
    scwin.ds_retrieveResult4_UseFilter        = false;
    scwin.ds_agreementVolumeResults_UseFilter = false;

    //UDC 그리드 팝업 호출 시 row값
    scwin.f_commCdPopupRow = 0;
};

/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = function() {
    //공통코드 추가
    const codeOptions = [
           { grpCd: "SD060", compID: "acb_expClsCd"}    //수출입구분
          ,{ grpCd: "OP117", compID: "acb_shiftCd, gr_retrieveResult2:shiftClsCd" }           //Shift구분
          ,{ grpCd: "OP241", compID: "acb_wrkMthdCd, gr_retrieveResult2:wrkMthdCd, gr_retrieveResult2:viewWrkMthdCd" }  //작업방법
          ,{ grpCd: "LO102", compID: "gr_retrieveResult2:wageVolUnit", opt: {"range":"2,L"} } //하역노임실적 그리드 : 노임단위   
          ,{ grpCd: "OP283", compID: "gr_retrieveResult2:eqClssCd" }                          // 하역노임실적 그리드 : 장비종류
     ];
    $c.data.setCommonCode(codeOptions);

    //공통코드2 콤보박스 SET
    const codeOptions2 = [
        {   // 하역실적물량 그리드 : 작업단계1
            method: "getGridCombo",
            param1: "StevedoringWagesResultsEBC",
            param2: "retriveWrkStpList",
            compID: "gr_retrieveResult2:wrkStpCd1"
        },
        {   // 하역노임실적 그리드 : 작업단계2
            method: "getGridCombo",
            param1: "StevedoringWagesResultsEBC",
            param2: "retriveWrkStpList",
            compID: "gr_retrieveResult2:wrkStpCd2"
        },
        {   // 하역노임실적 그리드 : 작업단계3
            method: "getGridCombo",
            param1: "StevedoringWagesResultsEBC",
            param2: "retriveWrkStpList",
            compID: "gr_retrieveResult2:wrkStpCd3"
        },
        {   // 하역노임실적 그리드 : 작업단계4
            method: "getGridCombo",
            param1: "StevedoringWagesResultsEBC",
            param2: "retriveWrkStpList",
            compID: "gr_retrieveResult2:wrkStpCd4"
        },
        {   // 할증코드 그리드 : 기력
            method: "getGridCombo",
            param1: "StevedoringWagesResultsEBC",
            param2: "retriveHKindList",
            compID: "gr_retrieveResult3:viewEqClssCd"
        }
    ];
    $c.data.setGauceUtil(codeOptions2, scwin.callBackGauceUtil);


    scwin.setInit();

    acb_expClsCd.setValue("");
    acb_shiftCd.setValue("");
    scwin.today       = $c.date.getServerDateTime();
    ica_wrkDt.setValue(scwin.today);

    $c.gus.cfDisableBtnOnly([btn_add, btn_addRow, btn_deleteRow, btn_cancelRow, btn_autoLoad, btn_openUnionPopUp, btn_delete, btn_cancel, btn_allDeleteRow, btn_allCancelRow]);
    ed_cntLUnion.setReadOnly(true);

    //테스트 데이터
    // ed_cvsslMgntNo.setValue("A0605001");
    // ica_wrkDt.setValue("20060524");
};

/**
 * $c.data.setGauceUtil 함수의 콜백함수
 */
scwin.callBackGauceUtil = function() {
    dlt_gauceUtil_gr_retrieveResult3_viewEqClssCd.insertJSON(0, [{
        "code": "0",
        "name": "0",
        "rowStatus": "R"
    }]);
    dlt_gauceUtil_gr_retrieveResult3_viewEqClssCd.reform();
};

/**
 * 조회필드 CLEAR
 */
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search, null);
    ica_wrkDt.setValue(scwin.today);
    acb_clsCd.setValue("C");
};

/**
 * 조회버튼
 */
scwin.f_Retrieve = async function () {
    // 검색조건 필수 입력 체크
    // if (!$c.gus.cfValidate([ed_cvsslMgntNo, ica_wrkDt])) {
    //     return;
    // }
    let ret;
    ret = await $c.gus.cfValidate([ed_cvsslMgntNo, ica_wrkDt]);
    if (!ret) {
        return;
    }

    // ds_retrieveResult4.UseFilter = "false";
    // var strPath = "/ds.op.wrkrslts.wagewrkrslts.RetrieveStevedoringWagesResultsCMD.do";
    // sbm_retrieve.setAction = strPath;

    scwin.setInit();

    scwin.retrieve2 = 0;
    scwin.ds_retrieveResult4_UseFilter = false;
    // $c.sbm.setAction(sbm_retrieve, "/ds.op.wrkrslts.wagewrkrslts.RetrieveStevedoringWagesResultsCMD.do");
    $c.sbm.execute(sbm_retrieve);

    //TOBE scwin.sbm_retrieve_submitdone 로직에 추가
    // $c.gus.cfGoPrevPosition(ds_retrieveResult2, scwin.pos_groupCode);
    // ed_cntLUnion.value = '';
};

scwin.sbm_retrieve_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    gr_retrieveResult2.setNoResultMessageVisible(true);
    gr_retrieveResult3.setNoResultMessageVisible(true);
    let rowcnt = ds_retrieveResult2.getRowCount();

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        //asis : for=ds_retrieveResult1 event=OnLoadCompleted(rowcnt)
        ds_retrieveResult1.setRowPosition(0, event);
        //안써도 됨(주석처리함)
        //scwin.f_retrieveResult1(ds_retrieveResult1.getRowCount());
        scwin.lobranCd = ds_retrieveResult1.getCellData(0, "lobranCd");

        //asis : for=ds_retrieveResult2 event=OnRowPosChanged(row)
        //tobe : scwin.ds_retrieveResult2_onrowpositionchange 로 처리
        // ds_retrieveResult2.setRowPosition(rowcnt, event);
        gr_retrieveResult2.setFocusedCell(0, 0, false);

        //TOBE : 조회된 데이터 없는 경우 강제로 할증코드 그리드 타도록 처리
        if(rowcnt == 0) {
            scwin.ds_retrieveResult2_onrowpositionchange({"newRowIndex":0});
        }

        //asis : for=ds_retrieveResult2 event=OnLoadCompleted(rowcnt)
        await scwin.ds_retrieveResult2_OnLoadCompleted(rowcnt);

        //asis : for=ds_retrieveResult3 event=OnLoadCompleted(rowcnt)
        scwin.rFlag = 0;
        totalRows2.setValue(ds_retrieveResult3.getRowCount());

        //asis : for=ds_retrieveResult4 event=OnLoadCompleted(rowcnt)
        //$c.gus.cfCopyDataSet(ds_retrieveResult4, ds_retrieveResult5, "copyHeader=yes");
        //let result =  $c.gus.copy(ds_retrieveResult4, ds_retrieveResult5);
        ds_retrieveResult5.setJSON(ds_retrieveResult4.getAllJSON());
        await scwin.f_checkLunionInfo();

        scwin.ds_retrieveResult4_UseFilter = true;
        scwin.ds_retrieveResult4_OnFilter();

        //asis : for=tr_retrieve event=OnSuccess()
        if (scwin.lobranCd == "6AA") {
            // 부산인 경우, 협정물량 불러오기 
            await scwin.f_Retrieve3();
        }

        //asis : f_Retrieve() > tr_retrieve.Post() 이후 로직
        // $c.gus.cfGoPrevPosition(ds_retrieveResult2, scwin.pos_groupCode);
        gr_retrieveResult2.setFocusedCell(scwin.pos_groupCode, 0);
        ed_cntLUnion.setValue();
    }
};

scwin.sbm_retrieve_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};


/**
 * ds_retrieveResult2 OnLoadCompleted 호출(TOBE : sbm_retrieve_submitdone 추가)
 * ASIS : for=ds_retrieveResult2 event=OnLoadCompleted(rowcnt)
 */
scwin.ds_retrieveResult2_OnLoadCompleted = async function (count) {
    if(!scwin.f_checkLunion()) {
        return;
    }    
    ds_retrieveResult2.setRowPosition(0, event);
    //gr_retrieveResult2.setFocusedCell(0, 0, false);

    scwin.f_retrieveResult2(count);
    // cfShowTotalRows(totalRows, rowCnt1);
    totalRows1.setValue(count);   
    scwin.f_checkOpenUnionPopUp(count);
    scwin.f_checkOpenUnionPopUp2(count);        
    if (count > 0 ) {
        $c.gus.cfDisableBtnOnly([]) ;
        scwin.booleanMsg = false;
    }else {
        await $c.gus.cfAlertMsg("해당하는 하역노임실적이 없습니다.");
        scwin.booleanMsg = true;
    }
    $c.gus.cfEnableBtnOnly([btn_add]);
    $c.gus.cfEnableBtnOnly([btn_cancel, btn_delete]);
};


/**
 * 하역실적 불러오기 버튼
 * submit 성공 시 scwin.sbm_retrieve_submitdone
 */
scwin.f_Retrieve2 = async function () {
    // 검색조건 필수 입력 체크
    let ret;
    ret = await $c.gus.cfValidate([ed_cvsslMgntNo, ica_wrkDt]);
    if (!ret) {
        return;
    }

    // var strPath = "/ds.op.wrkrslts.wagewrkrslts.RetrieveStevedoringResultsCMD.do";
    // sbm_retrieve.setAction = strPath;
    // $c.sbm.execute(sbm_retrieve);
    // for (i = 1; ds_retrieveResult2.getRowCount() >= i; i++) {
        //type 1:insert
        // ds_retrieveResult2.UserStatus(i) = "1";
    // }

    //조회시 하역노임실적 초기화
    gr_retrieveResult2.setNoResultMessageVisible(false);
    ds_retrieveResult2.removeAll();
    totalRows1.setValue("0");

    scwin.retrieve2 = 1;
    // $c.sbm.setAction(sbm_retrieve2, "/ds.op.wrkrslts.wagewrkrslts.RetrieveStevedoringResultsCMD.do");
    $c.sbm.execute(sbm_retrieve2);

    //TOBE scwin.sbm_retrieve_submitdone2 로직에 추가
    // for (i=1; ds_retrieveResult2.CountRow>=i; i++) {
    //     ds_retrieveResult2.UserStatus(i) = "1" ;
    // }
};

scwin.sbm_retrieve_submitdone2 = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    gr_retrieveResult2.setNoResultMessageVisible(true);
    let rowcnt = ds_retrieveResult2.getRowCount();

    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        //asis : for=ds_retrieveResult2 event=OnRowPosChanged(row)
        //tobe : scwin.ds_retrieveResult2_onrowpositionchange 로 처리
        // ds_retrieveResult2.setRowPosition(rowcnt, event);
        gr_retrieveResult2.setFocusedCell(0, 0, false);


        //asis : for=ds_retrieveResult2 event=OnLoadCompleted(rowcnt)
        await scwin.ds_retrieveResult2_OnLoadCompleted(rowcnt);


        //asis : for=tr_retrieve event=OnSuccess()
        if (scwin.lobranCd == "6AA") {
            // 부산인 경우, 협정물량 불러오기 
            await scwin.f_Retrieve3();
        }

        //asis : f_Retrieve2() > tr_retrieve.Post() 이후 로직
        //모든행의 상태를 변경
        ds_retrieveResult2.modifyAllStatus("C");
    }
};

scwin.sbm_retrieve_submiterror2 = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};

/**
 * 협정 물량 불러오기
 */
scwin.f_Retrieve3 = async function () {
    // 검색조건 필수 입력 체크
    let ret;
    ret = await $c.gus.cfValidate([ed_cvsslMgntNo, ica_wrkDt]);
    if (!ret) {
        return;
    }

    if (!$c.gus.cfIsNull(ed_cntLUnion.getValue()) 
      && $c.gus.cfisNumberCnt(ed_cntLUnion.getValue()) == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_007, ["투입반원"]);
        ed_cntLUnion.setValue("");
    }

    // ds_agreedVolumeCondition.removeAll();
    // ds_agreedVolumeCondition.insertRow();

    // ds_agreedVolumeCondition.setCellData(1, "cvsslMgntNo", ed_cvsslMgntNo.getValue());
    // ds_agreedVolumeCondition.setCellData(1, "expimpClsCd", acb_expClsCd.getValue("code", acb_expClsCd.index));
    // ds_agreedVolumeCondition.setCellData(1, "isModifyOnly", "true");

    dma_agreedVolumeCondition.setEmptyValue();
    dma_agreedVolumeCondition.set("cvsslMgntNo" , ed_cvsslMgntNo.getValue());
    dma_agreedVolumeCondition.set("expimpClsCd" , acb_expClsCd.getValue());
    dma_agreedVolumeCondition.set("isModifyOnly", "true");

    await $c.sbm.execute(sbm_retrieveAgreedVolume);
};


/**
 * 저장 버튼
 */
scwin.f_Save = async function () {
    let ret;
    // if (!scwin.f_checkVal()) return;
    // if (!$c.gus.cfValidate([gr_retrieveResult2])) return;
    // if (!scwin.f_CheckSaveOverLap()) return;

    //TOBE 추가
    // if (ds_retrieveResult2.getModifiedIndex().length < 1 
    //  && ds_retrieveResult3.getModifiedIndex().length < 1) {
    //     return;
    // }

    ret = await scwin.f_checkVal();
    if(!ret) {
        return;
    }
    ret = await $c.gus.cfValidate([gr_retrieveResult2]);
    if(!ret) {
        return;
    }
    ret = await scwin.f_CheckSaveOverLap();
    if(!ret) {
        return;
    }

    for (let i=0; i<ds_retrieveResult2.getRowCount(); i++) {
        if (ds_retrieveResult2.getCellData(i, "reqClntNo") == "124992" || ds_retrieveResult2.getCellData(i, "reqClntNo") == "") {
        } else {
            await $c.gus.cfAlertMsg((i+1) + "번째 요청 화주를 다시 입력하십시요.");
            return;
        }
        if (acb_wrkMthdCd.getValue() == "AB" && ds_retrieveResult2.getCellData(i, "wrkQty") != 0 && ds_retrieveResult2.getCellData(i, "wageVolUnit") == "VAN") {
            if (ds_retrieveResult2.getCellData(i, "wrkQty") != Math.round(ds_retrieveResult2.getCellData(i, "wageVol"))) {
                await $c.gus.cfAlertMsg((i+1) + "번째에서 수량과 노임물량이 일치하지 않습니다.");
                return;
            }
        }
    }

    let row = ds_retrieveResult2.getRowPosition();    
    dma_condition_delete.setEmptyValue();
    dma_condition_delete.set("odrNo"        , ds_retrieveResult2.getCellData(row, "odrNo"));
    dma_condition_delete.set("shiftClsCd"   , ds_retrieveResult2.getCellData(row, "shiftClsCd"));
    dma_condition_delete.set("wrkDt"        , ica_wrkDt.getValue());
    // if (confirm("저장하시겠습니까?")) {
    if (await $c.win.confirm(MSG_CM_CRM_001)) {
        scwin.pos_groupCode = row;
	    sbm_save.userData1="noError";
        $c.sbm.execute(sbm_save);
    }
};

scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) {
        await $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
        return;
    }

    //저장 성공
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        // 결과내용
        let conseCntn = "";
        conseCntn = ds_agreementVolumeSaveResults.getCellData(0, "conseCntn"); 
        if ($c.gus.cfIsNull(conseCntn)) {
            await $c.gus.cfAlertMsg(MSG_CM_INF_001);
        } else {
            // $c.gus.cfAlertMsg(conseCntn.simpleReplace("##", "<br>"));
            await $c.gus.cfAlertMsg(conseCntn.replace(/##/g, "<br>"));
        }

        scwin.f_Retrieve();

        //동해지사인 경우에
        if ((ed_cvsslMgntNo.getValue()).substring(0, 1) == "F") {
            // console.log("저장 > 조회 > 삭제 로직 탑니까");
	        //sbm_delete.userData1="noError";
            $c.sbm.execute(sbm_delete);
        }
    }
};

scwin.sbm_save_submiterror = function (e) {
    $c.gus.cfAlertMsg(e.responseJSON.resultDataSet[1].Msg);
};


/**
 * 작업장정보 체크
 * TOBE 종료시간 체크
 */
scwin.f_checkVal = async function() {
    let row  = ds_retrieveResult2.getRowCount();
    let row3 = ds_retrieveResult3.getRowCount();

    // Header에 해당하는 작업장코드가 없는 경우, 저장이 안되도록 함.
    let vWrkPlNm = ds_retrieveResult1.getCellData(0, "wrkPlNm");

    // if (typeof (vWrkPlNm) == 'undefined' || vWrkPlNm == "") {
    if ($c.gus.cfIsNull(vWrkPlNm)) {
        $c.gus.cfAlertMsg("작업장 정보가 없습니다.");
        return false;
    }

    for (let i=0; i<row; i++) {
        // let stDate  = ds_retrieveResult2.getCellData(row, "wrkStDt")  + ds_retrieveResult2.getCellData(row, "wrkStHh");
        // let endDate = ds_retrieveResult2.getCellData(row, "wrkEndDt") + ds_retrieveResult2.getCellData(row, "wrkEndHh");
        let stDate  = ds_retrieveResult2.getCellData(i, "wrkStDt")  + ds_retrieveResult2.getCellData(i, "wrkStHh");
        let endDate = ds_retrieveResult2.getCellData(i, "wrkEndDt") + ds_retrieveResult2.getCellData(i, "wrkEndHh");
        if (Number(stDate) > Number(endDate)) {
            await $c.gus.cfAlertMsg((i+1) + "번째 Row의 종료시간을 시작시간보다 이후로 입력하십시오");
            return false;
        }
        if(!await $c.date.isDate(stDate)) {
            await $c.gus.cfAlertMsg("하역실적물량의" + (i+1) + "번째 데이터에서 시작시간은(는) 시가 잘못되었습니다.");
            return false;
        }
        if(!await $c.date.isDate(endDate)) {
            await $c.gus.cfAlertMsg("하역실적물량의" + (i+1) + "번째 데이터에서 종료시간은(는) 시가 잘못되었습니다.");
            return false;
        }
        //return true;
    }
    return true;

    scwin.ds_retrieveResult3_UseFilter = false;
    // for (let j=0; j<row3; j++) {
    //     ds_retrieveResult3.UseFilter = "false";
    // }
};

