scwin.udc_lunionOrgCd_callBackFunc = function (ret) {
    if (ret[0] != "N/A" && !$c.gus.cfIsNull(ret)) {
        ed_lunionOrgCd.setValue(ret[2]);//반코드
        ed_chiefNm.setValue(ret[4]);    //반장
    }else {
        ed_lunionOrgCd.setValue("");    //반코드
        ed_chiefNm.setValue("");        //반장
    }
};

