/**
 * 행삭제
 */
scwin.f_DeleteRow = async function () {
    let row       = ds_retrieveResult2.getRowPosition();
    let cntMember = ds_retrieveResult2.getCellData(row, "cntUnionMember");

    if (cntMember > 0) {
        await $c.gus.cfAlertMsg("해당 노임편성내역을 먼저 삭제 한 후 반 정보를 삭제할 수 있습니다.");
        return false;
    }
    // ds_retrieveResult2.DeleteMarked();
    // for (i = 1; i <= ds_retrieveResult3.getRowCount(); i++) {
    //     ds_retrieveResult3.deleteRow(i);
    // }
    if (ds_retrieveResult2.getRowStatus(row) == "C") {
        ds_retrieveResult2.removeRow(row)
        gr_retrieveResult2.setFocusedCell(row, 0);
    } else {
        ds_retrieveResult2.deleteRow(row);
        gr_retrieveResult2.setFocusedCell(row, 0);
    }
    let rowcnt1 = ds_retrieveResult2.getRowCount();
    totalRows1.setValue(rowcnt1);

    //할증 리스트 일괄 삭제 하기
    scwin.f_AllDeleteMarked();
};


scwin.btn_allDeleteRow_onclick = function (e) {
    scwin.f_AllDeleteMarked();
};
/**
 * 할증 리스트 일괄 삭제 하기
 */
scwin.f_AllDeleteMarked = function() {
    let insertRow = ds_retrieveResult3.getInsertedIndex();
    for(let i=insertRow.length-1; i>=0; i--) {
        ds_retrieveResult3.removeRow(insertRow[i]);
    }
    for (let i=0; i<ds_retrieveResult3.getRowCount(); i++) {
        ds_retrieveResult3.deleteRow(i);
    }
    let rowcnt2 = ds_retrieveResult3.getRowCount();
    totalRows2.setValue(rowcnt2);
};

scwin.btn_allCancelRow_onclick = function (e) {
    scwin.f_AllUndoMarked();
};

/**
 * 할증 리스트 일괄 삭제 취소하기
 */
scwin.f_AllUndoMarked = function() {
    // ds_retrieveResult3.undoAll();
    $c.data.undoAll(ds_retrieveResult3);
    let rowcnt2 = ds_retrieveResult3.getRowCount();
    totalRows2.setValue(rowcnt2);
};

/**
 * 선택한  Chk 항목만큼  할증 리스트 삭제 하기
 * ASIS 사용안함
 */
scwin.f_deleteItem = function() {
    let cntChk = 0;
    let rowCnt = ds_retrieveResult2.getRowCount();
    for (let i=0; i<rowCnt; i++) {
        if (ds_retrieveResult2.getCellData(i, "chk") == "T") {
            cntChk++;
        }
    }
    //하역실적등록 Check Count 가 0 보다 크면 일괄 삭제 처리 함.
    if (cntChk > 0) {
        //하역실적등록 Check Count
        for (let i=0; i<rowCnt; i++) {
            if (ds_retrieveResult2.getCellData(i, "chk") == "T") {
                for (let j=0; j<ds_retrieveResult3.getRowCount(); j++) {
                    // ds_retrieveResult3.deleteRow(j);
                    if (ds_retrieveResult3.getRowStatus(j) == "C") {
                        ds_retrieveResult3.removeRow(j)
                    } else {
                        ds_retrieveResult3.deleteRow(j);
                    }
                }
            }
        }
    } else {
        // ds_retrieveResult3.DeleteMarked();
        let row = ds_retrieveResult3.getRowPosition();
        if (ds_retrieveResult3.getRowStatus(row) == "C") {
            ds_retrieveResult3.removeRow(row)
        } else {
            ds_retrieveResult3.deleteRow(row);
        }
    }
};

/**
 * 취소버튼(btn_cancel) 하역노임실적, 할증코드 그리드
 */
scwin.f_Undo = function() {
    // ds_retrieveResult2.UndoMarked();
    // ds_retrieveResult3.undoAll();
    // if (ds_retrieveResult2.UserStatus(ds_retrieveResult2.getRowPosition) == 0) {
    //     ds_retrieveResult3.UseFilter = "true";
    //     ds_retrieveResult3.filter();
    // }
    $c.data.undoRow(ds_retrieveResult2, false);
    $c.data.undoAll(ds_retrieveResult3);
    if (ds_retrieveResult2.getRowStatus(ds_retrieveResult2.getRowPosition()) == "R") {
        scwin.ds_retrieveResult3_UseFilter = true;
        scwin.ds_retrieveResult3_OnFilter();
    }

    let rowcnt1 = ds_retrieveResult2.getRowCount();
    totalRows1.setValue(rowcnt1);
    let rowcnt2 = ds_retrieveResult3.getRowCount();
    totalRows2.setValue(rowcnt2);
};

