                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , "F"					// 전체검색허용여부	("F")
                , "품목,품목코드,품목"  // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;

        case 2:
            // 하역노임실적 그리드 노임품목 코드 검색
            ds_retrieveResult2.setCellData(row, "wageGoodsCd", "");
            ds_retrieveResult2.setCellData(row, "wageGoodsNm", "");
            udc_comCode.setSelectId("retrieveCommInfo"); // XML상의 SELECT ID
            udc_comCode.cfCommonPopUp(scwin.udc_comCode_wageGoodsNm_callBackFunc    // 콜백 함수
                // , ds_retrieveResult2.getCellData(row, "wageGoodsCd")					// 화면에서의 ??? Code Element의	Value
                // , ds_retrieveResult2.getCellData(row, "wageGoodsNm")					// 화면에서의 ??? Name Element의	Value
                , data					// 화면에서의 ??? Code Element의	Value
                , dataNm				// 화면에서의 ??? Name Element의	Value
                , close				    // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서
                , null					// 보여주는 각 컬럼들의 폭
                , null					// 컬럼중에서 숨기는	컬럼 지정
                , ",,,T3"				// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능   ",,,T
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이
                , null					// 윈도우 위치 Y좌표
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , "F"					// 전체검색허용여부	("F")
                , "품목,품목코드,품목"	// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;

        case 3:
            // 하역노임실적 그리드 반 코드 검색
            var strParam = "";
            strParam = "" + "," + ds_retrieveResult2.getCellData(row, "wrkPlCd");

            ds_retrieveResult2.setCellData(row, "lunionOrgCd" , "");        //반코드
            ds_retrieveResult2.setCellData(row, "lunionOrgCd2", "");        //반코드(selectBox)
            ds_retrieveResult2.setCellData(row, "chiefNm"     , "");        //반장명
            ds_retrieveResult2.setCellData(row, "chiefExceptStaffCnt", ""); //반장외인원수

            udc_comCode.setSelectId("wageLunionOrgCdLevel3"); // XML상의 SELECT ID
            udc_comCode.cfCommonPopUp(scwin.udc_comCode_lunionOrgCd_callBackFunc	// 콜백 함수
                , data	                // 화면에서의 ??? Code Element의	Value
                , dataNm				// 화면에서의 ??? Name Element의	Value
                , close					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서	
                , null					// 보여주는 각 컬럼들의 폭	
                , null					// 컬럼중에서 숨기는	컬럼 지정	
                , strParam				// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , 500					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null					// 윈도우 위치 Y좌표	
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , "F"					// 전체검색허용여부	("F")
                , null				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );

            break;

        default:
            break;
    }
};

