/**
 * 그리드에서 달력팝업 & 품목팝업 호출
 */
// scwin.f_OpenCommPopup = function (row, colId) {
scwin.f_OpenCommPopup = function (row, colId, data, close) {
    if (colId == "commNm") {
        scwin.f_commCdPopup(row, 1, "", data, close);
    }

    if (colId == "wageGoodsNm") {
        scwin.f_commCdPopup(row, 2, "", data, close);
    }

    if (colId == "wageAgrmntDt" || colId == "adptStDt" || colId == "adptEndDt") {
        //달력팝업호출 TOBE 없음
        // cfOpenCalendar(gr_retrieveStevedoring, row, colId);
    }

    if (colId == "wrkStDt") {
        //달력팝업호출 TOBE 없음
        // cfOpenCalendar(gr_retrieveResult2, row, colId);
    } else if (colId == "wrkEndDt") {
        //달력팝업호출 TOBE 없음
        // cfOpenCalendar(gr_retrieveResult2, row, colId);
    }

    if (colId == "wrkStpCd1" ||
        colId == "wrkStpCd2" ||
        colId == "wrkStpCd3" ||
        colId == "wrkStpCd4" ||
        colId == "wrkMthdCd" ||
        colId == "wageVolUnit" ||
        colId == "shiftClsCd" ||
        colId == "lunionOrgCd" ||
        colId == "wageGoodsNm" ||
        colId == "commNm" ||
        colId == "eqClssCd") {
        if (!scwin.f_CheckOverLap(row, colId)) {
            return;
        }
        scwin.f_changeChangeCd(row, colId);
    }
    if (scwin.lobranCd == "6AA" && colId == "lunionOrgCd") {
        // scwin.f_commCdPopup(row, 3);
        scwin.f_commCdPopup(row, 3, data, data, close);
    }
};

/**
 * 하역노임실적 값이 변경되면 일용정보(인원정보 제외), 할증코드 dataList에도 값 적용
 */
scwin.f_changeChangeCd = function (row, colId) {
    var rows  = ds_retrieveResult3.getRowCount();
    var value = ds_retrieveResult2.getCellData(row, colId);
    for (let i=0; i <rows; i++) {
        ds_retrieveResult3.setCellData(i, colId, value);
    }
};

/**
 * 하역노임실적 행추가후 중복체크
 */
scwin.f_CheckOverLap = async function (row, colId) {
    let rowCnt = ds_retrieveResult2.getRowCount();
    for (let i=0; i<rowCnt; i++) {
        let wrkMthdCd   = ds_retrieveResult2.getCellData(i, "wrkMthdCd");
        let shiftClsCd  = ds_retrieveResult2.getCellData(i, "shiftClsCd");
        let lunionOrgCd = ds_retrieveResult2.getCellData(i, "lunionOrgCd");
        let commCd      = ds_retrieveResult2.getCellData(i, "commCd");
        let holdNo      = ds_retrieveResult2.getCellData(i, "holdNo");
        let wageGoodsCd = ds_retrieveResult2.getCellData(i, "wageGoodsCd");
        let wrkQty      = ds_retrieveResult2.getCellData(i, "wrkQty");
        let wrkWt       = ds_retrieveResult2.getCellData(i, "wrkWt");
        let wrkCbm      = ds_retrieveResult2.getCellData(i, "wrkCbm");
        let wageVol     = ds_retrieveResult2.getCellData(i, "wageVol");
        let wageVolUnit = ds_retrieveResult2.getCellData(i, "wageVolUnit");
        let eqClssCd    = ds_retrieveResult2.getCellData(i, "eqClssCd");
        let wrkStpCd1   = ds_retrieveResult2.getCellData(i, "wrkStpCd1");
        let wrkStpCd2   = ds_retrieveResult2.getCellData(i, "wrkStpCd2");
        let wrkStpCd3   = ds_retrieveResult2.getCellData(i, "wrkStpCd3");
        let wrkStpCd4   = ds_retrieveResult2.getCellData(i, "wrkStpCd4");
        let wrkEndDt    = ds_retrieveResult2.getCellData(i, "wrkEndDt");
        let wrkStDt     = ds_retrieveResult2.getCellData(i, "wrkStDt");
        let wrkEndHh    = ds_retrieveResult2.getCellData(i, "wrkEndHh");
        let wrkStHh     = ds_retrieveResult2.getCellData(i, "wrkStHh");

        for (let j=i+1; j<rowCnt; j++) {
            let wrkMthdCdNext   = ds_retrieveResult2.getCellData(j, "wrkMthdCd");   // 작업방법
            let shiftClsCdNext  = ds_retrieveResult2.getCellData(j, "shiftClsCd");  // 주야간구분
            let lunionOrgCdNext = ds_retrieveResult2.getCellData(j, "lunionOrgCd"); // 노조조직코드
            let commCdNext      = ds_retrieveResult2.getCellData(j, "commCd");      // 품명
            let holdNoNext      = ds_retrieveResult2.getCellData(j, "holdNo");      // hold
            let wageGoodsCdNext = ds_retrieveResult2.getCellData(j, "wageGoodsCd"); // 노임품명
            let wrkQtyNext      = ds_retrieveResult2.getCellData(j, "wrkQty");      // 수량
            let wrkWtNext       = ds_retrieveResult2.getCellData(j, "wrkWt");       // 중량
            let wrkCbmNext      = ds_retrieveResult2.getCellData(j, "wrkCbm");      // CBM
            let wageVolNext     = ds_retrieveResult2.getCellData(j, "wageVol");     // 노임물량
            let wageVolUnitNext = ds_retrieveResult2.getCellData(j, "wageVolUnit"); // 노임단위
            let eqClssCdNext    = ds_retrieveResult2.getCellData(j, "eqClssCd");    // 장비분류
            let wrkStpCd1Next   = ds_retrieveResult2.getCellData(j, "wrkStpCd1");
            let wrkStpCd2Next   = ds_retrieveResult2.getCellData(j, "wrkStpCd2");
            let wrkStpCd3Next   = ds_retrieveResult2.getCellData(j, "wrkStpCd3");
            let wrkStpCd4Next   = ds_retrieveResult2.getCellData(j, "wrkStpCd4");
            let wrkEndDtNext    = ds_retrieveResult2.getCellData(j, "wrkEndDt");    // 종료일
            let wrkStDtNext     = ds_retrieveResult2.getCellData(j, "wrkStDt");     // 시작일
            let wrkEndHhNext    = ds_retrieveResult2.getCellData(j, "wrkEndHh");    // 종료일
            let wrkStHhNext     = ds_retrieveResult2.getCellData(j, "wrkStHh");     // 시작일

            if (wrkMthdCd == wrkMthdCdNext 
             && shiftClsCd == shiftClsCdNext 
             && lunionOrgCd == lunionOrgCdNext 
             && commCd == commCdNext 
             && holdNo == holdNoNext 
             && wageGoodsCd == wageGoodsCdNext 
             && wrkQty == wrkQtyNext 
             && wrkWt == wrkWtNext 
             && wrkCbm == wrkCbmNext 
             && wageVol == wageVolNext 
             && wageVolUnit == wageVolUnitNext 
             && eqClssCd == eqClssCdNext) {
                if (wrkStpCd1 == wrkStpCd1Next 
                 && wrkStpCd2 == wrkStpCd2Next 
                 && wrkStpCd3 == wrkStpCd3Next 
                 && wrkStpCd4 == wrkStpCd4Next 
                 && wrkEndDt == wrkEndDtNext 
                 && wrkStDt == wrkStDtNext 
                 && wrkEndHh == wrkEndHhNext 
                 && wrkStHh == wrkStHhNext) {
                    // $c.win.alert(i + "번째 행의 " + gr_retrieveResult2.ColumnProp(colId, 'Name') + "와 " + j + "번째 행의 " + gr_retrieveResult2.ColumnProp(colId, 'Name') + "가 중복됩니다.");
                    // ds_retrieveResult2.setCellData(j, colId, "");
                    // ds_retrieveResult2.setRowPosition = j;
                    // gr_retrieveResult2.SetColumn(colId);
                    // gr_retrieveResult2.Focus();
                    await $c.gus.cfAlertMsg((i+1) + "번째 행의 " + gr_retrieveResult2.getHeaderValue(colId + "Hd") + "와 " + (j+1) + "번째 행의 " + gr_retrieveResult2.getHeaderValue(colId + "Hd") + "가 중복됩니다.");
                    ds_retrieveResult2.setCellData(j, colId, "");
                    ds_retrieveResult2.setRowPosition(j);
                    gr_retrieveResult2.setFocusedCell(j, colId, true);
                    return false;
                }
            }
        } // for
    } // for
    return true;
};

