             && commCd == commCdNext 
             && holdNo == holdNoNext 
             && wageGoodsCd == wageGoodsCdNext 
             && wrkQty == wrkQtyNext 
             && wrkWt == wrkWtNext 
             && wrkCbm == wrkCbmNext 
             && wageVol == wageVolNext 
             && wageVolUnit == wageVolUnitNext 
             && eqClssCd == eqClssCdNext 
             && wrkEndDt == wrkEndDtNext 
             && wrkStDt == wrkStDtNext 
             && wrkEndHh == wrkEndHhNext 
             && wrkStHh == wrkStHhNext) {
                if (wrkStpCd1 == wrkStpCd1Next 
                 && $c.gus.cfIsNull(wrkStpCd2Next)
                 && $c.gus.cfIsNull(wrkStpCd3Next)
                 && $c.gus.cfIsNull(wrkStpCd4Next)) {
                    // $c.win.alert(j + "번째 행의 " + gr_retrieveResult2.ColumnProp("wrkStpCd1", 'Name') + "가 중복됩니다.");
                    // ds_retrieveResult2.setCellData(j, "wrkStpCd1", "");
                    // ds_retrieveResult2.setRowPosition = j;
                    // gr_retrieveResult2.SetColumn("wrkStpCd1");
                    // gr_retrieveResult2.Focus();
                    await $c.gus.cfAlertMsg((j+1) + "번째 행의 " + gr_retrieveResult2.getHeaderValue("wrkStpCd1Hd") + "가 중복됩니다.");
                    ds_retrieveResult2.setCellData(j, "wrkStpCd1", "");
                    ds_retrieveResult2.setRowPosition(j);
                    gr_retrieveResult2.setFocusedCell(j, "wrkStpCd1", true);
                    return false;
                }

                if (wrkStpCd1Next == wrkStpCd1 
                 && wrkStpCd2Next == wrkStpCd2 
                 && $c.gus.cfIsNull(wrkStpCd3Next)
                 && $c.gus.cfIsNull(wrkStpCd4Next)) {
                    // $c.win.alert(j + "번째 행의 " + gr_retrieveResult2.ColumnProp("wrkStpCd2", 'Name') + "가 중복됩니다.");
                    // ds_retrieveResult2.setCellData(j, "wrkStpCd2", "");
                    // ds_retrieveResult2.setRowPosition = j;
                    // gr_retrieveResult2.SetColumn("wrkStpCd2");
                    // gr_retrieveResult2.Focus();
                    await $c.gus.cfAlertMsg((j+1) + "번째 행의 " + gr_retrieveResult2.getHeaderValue("wrkStpCd2Hd") + "가 중복됩니다.");
                    ds_retrieveResult2.setCellData(j, "wrkStpCd2", "");
                    ds_retrieveResult2.setRowPosition(j);
                    gr_retrieveResult2.setFocusedCell(j, "wrkStpCd2", true);
                    return false;
                }

                if (wrkStpCd1Next == wrkStpCd1 
                 && wrkStpCd2Next == wrkStpCd2 
                 && wrkStpCd3Next == wrkStpCd3 
                 && $c.gus.cfIsNull(wrkStpCd4Next)) {
                    // $c.win.alert(j + "번째 행의 " + gr_retrieveResult2.ColumnProp("wrkStpCd3", 'Name') + "가 중복됩니다.");
                    // ds_retrieveResult2.setCellData(j, "wrkStpCd3", "");
                    // ds_retrieveResult2.setRowPosition = j;
                    // gr_retrieveResult2.SetColumn("wrkStpCd3");
                    // gr_retrieveResult2.Focus();

                    await $c.gus.cfAlertMsg((j+1) + "번째 행의 " + gr_retrieveResult2.getHeaderValue("wrkStpCd3Hd") + "가 중복됩니다.");
                    ds_retrieveResult2.setCellData(j, "wrkStpCd3", "");
                    ds_retrieveResult2.setRowPosition(j);
                    gr_retrieveResult2.setFocusedCell(j, "wrkStpCd3", true);
                    return false;
                }

                if (wrkStpCd1Next == wrkStpCd1 
                 && wrkStpCd2Next == wrkStpCd2 
                 && wrkStpCd3Next == wrkStpCd3 
                 && wrkStpCd4Next == wrkStpCd4) {
                    // $c.win.alert(j + "번째 행의 " + gr_retrieveResult2.ColumnProp("wrkStpCd4", 'Name') + "가 중복됩니다.");
                    // ds_retrieveResult2.setCellData(j, "wrkStpCd4", "");
                    // ds_retrieveResult2.setRowPosition = j;
                    // gr_retrieveResult2.SetColumn("wrkStpCd4");
                    // gr_retrieveResult2.Focus();
                    await $c.gus.cfAlertMsg((j+1) + "번째 행의 " + gr_retrieveResult2.getHeaderValue("wrkStpCd4Hd") + "가 중복됩니다.");
                    ds_retrieveResult2.setCellData(j, "wrkStpCd4", "");
                    ds_retrieveResult2.setRowPosition(j);
                    gr_retrieveResult2.setFocusedCell(j, "wrkStpCd4", true);
                    return false;
                }
            }

        } // for

    } // for

    return true;
};

/**
 * 그리드에서 달력팝업 & 품목팝업 호출
 */
// scwin.f_AutoPopup = function (row, colId, oldData) {
scwin.f_AutoPopup = function (row, colId, oldData, newData) {
// console.log("scwin.f_AutoPopup > colId : "+colId + " > newData : "+newData +" > oldData : "+oldData);
    if (colId == "commCd" || colId == "commNm") {
        if (!$c.gus.cfIsNull(newData)
         && newData != oldData ) {
            ds_retrieveResult2.setCellData(row, "commNm", "");
            // scwin.f_commCdPopup(row, 1);
            scwin.f_commCdPopup(row, 1, newData, "", "T");
        } else if ($c.gus.cfIsNull(newData)) {
            ds_retrieveResult2.setCellData(row, "commCd", "");
            ds_retrieveResult2.setCellData(row, "commNm", "");
        }
    }

    if (colId == "wageGoodsCd" || colId == "wageGoodsNm") {
        if (!$c.gus.cfIsNull(newData)
         && newData != oldData ) {
            ds_retrieveResult2.setCellData(row, "wageGoodsNm", "");
            // scwin.f_commCdPopup(row, 2);
            scwin.f_commCdPopup(row, 2, newData, "", "T");
        } else if ($c.gus.cfIsNull(newData)) {
            ds_retrieveResult2.setCellData(row, "wageGoodsCd", "");
            ds_retrieveResult2.setCellData(row, "wageGoodsNm", "");
        }
    }

    if (colId == "wageGoodsCd" || colId == "wageGoodsNm") {
        scwin.f_changeChangeCd(row, "wageGoodsCd");
        scwin.f_changeChangeCd(row, "wageGoodsNm");
    } else if (colId == "commCd" || colId == "commNm") {
        scwin.f_changeChangeCd(row, "commCd");
        scwin.f_changeChangeCd(row, "commNm");
    } else if (colId == "wageVol" || colId == "wrkStDt" || colId == "wrkStHh" || colId == "wrkEndDt" || colId == "wrkEndHh" || colId == "holdNo") {
        scwin.f_changeChangeCd(row, colId);
    }

    if (scwin.lobranCd == "6AA" 
     && colId == "lunionOrgCd") {
        // scwin.f_commCdPopup(row, 3);
        scwin.f_commCdPopup(row, 3, newData, newData, "T");
    }
};


/**
 * 작업단계 체크
 */
scwin.f_wrkPlCdCheck = function (row, colId) {
    if (colId == "wrkStpCd2") {
        if ($c.gus.cfIsNull(ds_retrieveResult2.getCellData(row, "wrkStpCd1"))) {
            // gr_retrieveResult2.setColumnDefaultValue('wrkStpCd2', 'Edit') = "NONE";
            gr_retrieveResult2.setCellReadOnly(row, "wrkStpCd2", true);
        } else if (!$c.gus.cfIsNull(ds_retrieveResult2.getCellData(row, "wrkStpCd1"))) {
            // gr_retrieveResult2.setColumnDefaultValue('wrkStpCd2', 'Edit') = "ANY";
            gr_retrieveResult2.setCellReadOnly(row, "wrkStpCd2", false);
        }
    }

    if (colId == "wrkStpCd3") {
        if ($c.gus.cfIsNull(ds_retrieveResult2.getCellData(row, "wrkStpCd2"))) {
            // gr_retrieveResult2.setColumnDefaultValue('wrkStpCd3', 'Edit') = "NONE";
            gr_retrieveResult2.setCellReadOnly(row, "wrkStpCd3", true);
        } else if (!$c.gus.cfIsNull(ds_retrieveResult2.getCellData(row, "wrkStpCd1"))) {
            // gr_retrieveResult2.setColumnDefaultValue('wrkStpCd3', 'Edit') = "ANY";
            gr_retrieveResult2.setCellReadOnly(row, "wrkStpCd3", false);
        }
    }

    if (colId == "wrkStpCd4") {
        if ($c.gus.cfIsNull(ds_retrieveResult2.getCellData(row, "wrkStpCd3"))) {
            // gr_retrieveResult2.setColumnDefaultValue('wrkStpCd4', 'Edit') = "NONE";
            gr_retrieveResult2.setCellReadOnly(row, "wrkStpCd4", true);
        } else if (!$c.gus.cfIsNull(ds_retrieveResult2.getCellData(row, "wrkStpCd1"))) {
            // gr_retrieveResult2.setColumnDefaultValue('wrkStpCd4', 'Edit') = "ANY";
            gr_retrieveResult2.setCellReadOnly(row, "wrkStpCd4", false);
        }
    }

    if (colId == "shiftClsCd") {
        let status = ds_retrieveResult2.getRowStatusValue(row);
        //상태값[0] == 초기값("R")
        if (status == 0) {
            // gr_retrieveResult2.setColumnDefaultValue('shiftClsCd', 'Edit') = "NONE";
            gr_retrieveResult2.setCellReadOnly(row, "shiftClsCd", true);
        } else if (status > 0) {
            // gr_retrieveResult2.setColumnDefaultValue('shiftClsCd', 'Edit') = "ANY";
            gr_retrieveResult2.setCellReadOnly(row, "shiftClsCd", false);
        }
    }
};

/**
