    args[i++] = ds_retrieveResult2.getCellData(row, "wrkStpCd3");
    args[i++] = ds_retrieveResult2.getCellData(row, "wrkStpCd4");
    args[i++] = ds_retrieveResult2.getCellData(row, "wrkMthdCd");
    args[i++] = ds_retrieveResult2.getCellData(row, "wrkQty");
    args[i++] = ds_retrieveResult2.getCellData(row, "wageVol");
    args[i++] = ds_retrieveResult2.getCellData(row, "impExpClsCd");
    args[i++] = ds_retrieveResult2.getCellData(row, "eqClssCd");
    args[i++] = ds_retrieveResult2.getCellData(row, "wageGoodsCd");
    args[i++] = ds_retrieveResult2.getCellData(row, "wageVolUnit");

    //resultAdd = window.showModalDialog('/ds/op/wrkrslts/wagewrkrslts/op_307_01_18p.jsp?paramTitle=작업장별 할증요율 조회&param=1',args,"dialogWidth:900px; dialogHeight:500px; status:No");
    let opts = {};
    opts.width  = "1200";
    opts.height = "740";
    opts.id = "popScrt";
    opts.title = "작업장별 할증요율 조회";
    opts.popupName = "작업장별 할증요율 조회";
    opts.scrollbars = false;
    opts.type      = "browserPopup";

    //그냥 배열로 보냄 => 받을 때 $p.getAllParameter().paramData.data
    // let data = {};
    // data.data   = args;
    // data.param1 = 1;
    let resultAdd = await $c.win.openPopup("/ui/ds/op/wrkrslts/wagewrkrslts/op_307_01_18p.xml", opts, args);
    if (resultAdd != null && resultAdd[0] != "N/A") {
        scwin.f_AddRow2(resultAdd);
    }
};

/**
 * 취소버튼(btn_cancelRow) 할증코드 그리드
 * asis : onClick="ds_retrieveResult3.UndoMarked()"
 */
scwin.f_Undo3 = function() {
    let row = ds_retrieveResult3.getRowPosition();
    if(ds_retrieveResult3.getRowStatus(row) == "C") {
        ds_retrieveResult3.removeRow(row);
    }else {
        ds_retrieveResult3.undoRow(row);
        gr_retrieveResult3.setFocusedCell(row, 0);
    }
    totalRows2.setValue(ds_retrieveResult3.getRowCount());
};

/**
 * 삭제버튼(btn_cancelRow) 할증코드 그리드
 * asis : onClick="ds_retrieveResult3.DeleteMarked()"
 */
scwin.f_DeleteRow3 = function() {
    let row = ds_retrieveResult3.getRowPosition();
    if(ds_retrieveResult3.getRowStatus(row) == "C") {
        ds_retrieveResult3.removeRow(row);
    }else {
        ds_retrieveResult3.deleteRow(row);
        gr_retrieveResult3.setFocusedCell(row, 0);
    }
    totalRows2.setValue(ds_retrieveResult3.getRowCount());
};


