/**
 * 할증항목 자동 불러오기
 */
scwin.f_AutoLoad = async function (type) {
    scwin.autoLoadType = type;

    var wageRsltsSeq = -1;
    let checkCnt     = 0;
    let k            = 0;

    if (scwin.isChecked) {
        k = 0;
    } else {
        k = ds_retrieveResult2.getRowPosition();
    }

    scwin.autoLoadPostCnt = 0;

    for (k; k < ds_retrieveResult2.getRowCount(); k++) {
        if ((ds_retrieveResult2.getCellData(k, "chk") == "T") || (k == ds_retrieveResult2.getRowPosition())) {

            wageRsltsSeq = ds_retrieveResult2.getCellData(k, "wageRsltsSeq");

            if ($c.gus.cfIsNull(wageRsltsSeq) || wageRsltsSeq == 0) {
                await $c.win.alert('하역노임실적을 저장한 후 할증을 추가할 수 있습니다.');
                return;
            }

            dma_conditionAuto.set("wrkPlCd"             , ds_retrieveResult2.getCellData(k, "wrkPlCd"));
            dma_conditionAuto.set("odrNo"               , ds_retrieveResult2.getCellData(k, "odrNo"));
            dma_conditionAuto.set("wrkDt"               , ds_retrieveResult2.getCellData(k, "wrkDt"));
            dma_conditionAuto.set("upperWageRsltsSeq"   , wageRsltsSeq);
            dma_conditionAuto.set("wageGoodsCd"         , ds_retrieveResult2.getCellData(k, "wageGoodsCd"));
            dma_conditionAuto.set("eqClssCd"            , ds_retrieveResult2.getCellData(k, "eqClssCd"));
            dma_conditionAuto.set("expimpClsCd"         , ds_retrieveResult2.getCellData(k, "impExpClsCd"));
            dma_conditionAuto.set("wtTenfrAdptSt"       , ds_retrieveResult2.getCellData(k, "wtTenfrAdptSt"));
            dma_conditionAuto.set("wtTenfrAdptEnd"      , ds_retrieveResult2.getCellData(k, "wtTenfrAdptEnd"));
            dma_conditionAuto.set("wrkMthdCd"           , ds_retrieveResult2.getCellData(k, "wrkMthdCd"));
            dma_conditionAuto.set("wrkStpCd1"           , ds_retrieveResult2.getCellData(k, "wrkStpCd1"));
            dma_conditionAuto.set("wrkStpCd2"           , ds_retrieveResult2.getCellData(k, "wrkStpCd2"));
            dma_conditionAuto.set("wrkStpCd3"           , ds_retrieveResult2.getCellData(k, "wrkStpCd3"));
            dma_conditionAuto.set("wrkStpCd4"           , ds_retrieveResult2.getCellData(k, "wrkStpCd4"));
            dma_conditionAuto.set("shiftClsCd"          , ds_retrieveResult2.getCellData(k, "shiftClsCd"));
            dma_conditionAuto.set("wageVol"             , ds_retrieveResult2.getCellData(k, "wageVol"));
            dma_conditionAuto.set("wrkQty"              , ds_retrieveResult2.getCellData(k, "wrkQty"));
            dma_conditionAuto.set("wageVolUnit"         , ds_retrieveResult2.getCellData(k, "wageVolUnit"));
            dma_conditionAuto.set("wrkWt"               , ds_retrieveResult2.getCellData(k, "wrkWt"));

            scwin.autoLoadPostCnt++;

            await $c.sbm.execute(sbm_retrieveAuto);


            //asis : for=ds_retrieveResultAuto event=OnLoadCompleted(rowcnt) 이후 로직
            scwin.f_retrieveResultAuto(ds_retrieveResultAuto.getRowCount());


            //asis : f_AutoLoad() > tr_retrieveAuto.Post() 이후 로직
            for (let i=0; i<ds_retrieveResultAuto.getRowCount(); i++) {
                if (ds_retrieveResultAuto.getCellData(i, "chk") == 0) {
                    scwin.ds_retrieveResult3_UseFilter = false;

                    let newRow = ds_retrieveResult3.insertRow();
                    ds_retrieveResult3.setRowPosition(newRow);
                    ds_retrieveResult3.setCellData(newRow, "goodsCd"            , ds_retrieveResult2.getCellData(k, "goodsCd"));
                    ds_retrieveResult3.setCellData(newRow, "scAmt"              , ds_retrieveResultAuto.getCellData(i, "scAmt"));
                    ds_retrieveResult3.setCellData(newRow, "scRt"               , ds_retrieveResultAuto.getCellData(i, "scRt"));
