/**
 * 하역투입반원등록 작업 확인
 */
scwin.f_checkLunion = async function () {
    let row = ds_retrieveResult2.getRowCount();
    for (let i=0; i<row; i++) {
        let lunion = ds_retrieveResult2.getCellData(i, "lunionOrgCd");
        if ($c.gus.cfIsNull(lunion)) {
            await $c.gus.cfAlertMsg("하역투입반원등록 작업을 먼저 실행하십시오.");
            ds_retrieveResult2.removeAll();
            $c.gus.cfDisableBtnOnly([]);
            return false;
        }
    }
    return true;
};

