/**
 * 노조 편성내역 조정팝업창 띄우기
 */
scwin.f_openUnionPopUp = async function () {
    // if (ds_retrieveResult2.isUpdated) {    
    if (!ds_retrieveResult2.getModifiedIndex().length < 1) {
        if (await $c.win.confirm(MSG_CM_CRM_015)) {
            await scwin.f_Save();
        }else {
            return;
        }
    }
    let args = new Array();
    let row  = ds_retrieveResult2.getRowPosition();
    args[0]  = ds_retrieveResult2.getCellData(row, "odrNo");
    args[1]  = ds_retrieveResult2.getCellData(row, "lunionOrgCd");
    args[2]  = ds_retrieveResult2.getCellData(row, "wrkDt");
    args[3]  = ds_retrieveResult2.getCellData(row, "stvWrkIndictNo");
    args[4]  = acb_expClsCd.getValue();
    args[5]  = acb_shiftCd.getValue();
    args[6]  = 0;
    args[7]  = ds_retrieveResult1.getCellData(0   , "wrkPlNm");
    args[8]  = ds_retrieveResult1.getCellData(0   , "cvsslMgntNo");
    args[11] = ds_retrieveResult2.getCellData(0  , "wrkPlCd");
    args[12] = ds_retrieveResult2.getCellData(row, "holdNo");

    // let rtnValues = window.showModalDialog('/ds/op/wrkrslts/wagewrkrslts/op_307_01_03p.jsp?paramTitle=노조 편성내역 조정팝업&check=', args, "dialogWidth:500px; dialogHeight:530px; status:No");
    // if (rtnValues != null) {
    //     scwin.f_Retrieve();
    // }
    let opts = {};
    opts.width  = "900";
    opts.height = "760";
    opts.id = "popLunionOrgCd";
    opts.title = "노조 편성내역 조정팝업";
    opts.popupName = "노조 편성내역 조정팝업";
    opts.scrollbars = false;
    opts.type      = "browserPopup";

    let rtnValues = await $c.win.openPopup("/ui/ds/op/wrkrslts/wagewrkrslts/op_307_01_03p.xml", opts, {"data":args, "check":null});
    if (rtnValues != null && rtnValues[0] != "N/A") {
        await scwin.f_Retrieve();
    }
};

