/**
 * 입력된 협정물량 관리번호에 해당하는 협정물량을  하역노임 실적 리스트에 등록
 */
// scwin.f_setAgreedVolumeData = function() {
scwin.f_setAgreedVolumeData = async function(dsRow2) {
    let cntrBulkClsCd = acb_clsCd.getValue();
    let inputRate = 1;
    // let dsRow2    = ds_retrieveResult2.getRowPosition();
//console.log("scwin.f_setAgreedVolumeData row : " + dsRow2 + ", scwin.isAgreementVolumeFilterClear : " + scwin.isAgreementVolumeFilterClear);
    if (acb_clsCd.getValue() == "C" || acb_clsCd.getValue() == "B") {
        // ds_agreementVolumeResults.UseFilter = "true";
        // ds_agreementVolumeResults.filter();
        scwin.ds_agreementVolumeResults_UseFilter = true;
        scwin.ds_agreementVolumeResults_OnFilter();
    }

    // 협정물량과 일치되는 데이터가 없으면 취소처리 함.
    if (ds_agreementVolumeResults.getRowCount() == 0 && scwin.isAgreementVolumeFilterClear == false) {
        await $c.gus.cfAlertMsg("입력하신 협정물량관리번호와 일치하는 협정물량이 없습니다. ");
        ds_retrieveResult2.setCellData(dsRow2, "agrVolmgntNo", "");
        return;
    }

    let wrkStDt     = ds_retrieveResult2.getCellData(dsRow2, "wrkStDt");    //시작일자
    let wrkStHh     = ds_retrieveResult2.getCellData(dsRow2, "wrkStHh");    //시작시간
    let wrkEndDt    = ds_retrieveResult2.getCellData(dsRow2, "wrkEndDt");   //종료일자
    let wrkEndHh    = ds_retrieveResult2.getCellData(dsRow2, "wrkEndHh");   //종료시간
    let shiftClsCd  = dma_condition.get("shiftClsCd");                      //Shift 구분
    let wageVolUnit = "";

    if (cntrBulkClsCd == "C") {
        wageVolUnit = "VAN";
    }else if (cntrBulkClsCd == "B") {
        wageVolUnit = "TON";
    }

    if (ds_retrieveResult2.getRowCount() == 1) {
        wrkStDt  = ica_wrkDt.getValue();
        wrkEndDt = ica_wrkDt.getValue();
        if (shiftClsCd == "D") {
            wrkStHh  = "0800";
            wrkEndHh = "1800";
        } else if (shiftClsCd == "N") {
            wrkStHh  = "1900";
            wrkEndHh = "2359";
        } else if (shiftClsCd == "M") {
            wrkStHh  = "2400";
            wrkEndHh = "0600";
        }
    }

    // 수량, CBM 값에 대해 1/n 처리함.
    for (let i=0; i<ds_agreementVolumeResults.getRowCount(); i++) {
        if (ds_agreementVolumeResults.getCellData(i, "rmdrQty") <= 0 
         || ds_retrieveResult2.getCellData(dsRow2, "wrkQty") < 0) {
            inputRate = 1;
        }else if (scwin.cntLUnion > inputRate) {
            inputRate = inputRate / scwin.cntLUnion;
        }else {
            inputRate = ds_retrieveResult2.getCellData(dsRow2, "wrkQty") / ds_agreementVolumeResults.getCellData(i, "rmdrQty");
        }

        let arrQtyValue = scwin.f_divideQTY(i);                                                     //수량
        let arrWtValue  = scwin.f_divideValue(ds_agreementVolumeResults.getCellData(i, "rmdrWt"));  // 협정물량 잔여 중량
        let arrCbmValue = scwin.f_divideValue(ds_agreementVolumeResults.getCellData(i, "rmdrCbm")); // 협정물량 잔여 CBM

        let wrkStpCd = ds_agreementVolumeResults.getCellData(i, "sellItemCd");                      // 0171: 선측하역료 , 0001 : 선내 하역료
        if (cntrBulkClsCd == "ALL") {
            cntrBulkClsCd = ds_agreementVolumeResults.getCellData(i, "cntrBulkClsCd");
            wageVolUnit = (cntrBulkClsCd == "C")?"VAN":"TON";
        }

        let newRow = 0;
        for (let j=1; j< scwin.cntLUnion; j++) {
            // if (i > 1) {
            if (i > 0) {
                newRow = ds_retrieveResult2.insertRow();
                ds_retrieveResult2.setRowPosition(newRow);
            }

            ds_retrieveResult2.setCellData(newRow, "wrkMthdCd", ds_agreementVolumeResults.getCellData(i, "wrkMthdCd"));
            ds_retrieveResult2.setCellData(newRow, "odrNo", ds_orderInfo.getCellData(1, "stvWageOdrNo"));
            ds_retrieveResult2.setCellData(newRow, "stvWrkIndictNo", ds_wrkIndictNo.getCellData(1, "wrkIndictNo")); //하역작업지시번호
            ds_retrieveResult2.setCellData(newRow, "impExpClsCd", ds_retrieveResult1.getCellData(1, "impExpClsCd")); //수출입구분코드
            ds_retrieveResult2.setCellData(newRow, "cvsslMgntNo", ed_cvsslMgntNo.getValue()); //본선관리 번호
            ds_retrieveResult2.setCellData(newRow, "wrkPlCd", ds_retrieveResult1.getCellData(1, "pierCd")); //작업장코드
            ds_retrieveResult2.setCellData(newRow, "wrkDt", ica_wrkDt.getValue()); //작업일시
            ds_retrieveResult2.setCellData(newRow, "shiftClsCd", shiftClsCd); //shift 값

            ds_retrieveResult2.setCellData(newRow, "agrVolmgntNo", ds_agreementVolumeResults.getCellData(i, "agrVolmgntNo")); //협정물량 관리번호
            ds_retrieveResult2.setCellData(newRow, "commCd", ds_agreementVolumeResults.getCellData(i, "commCd"));
            ds_retrieveResult2.setCellData(newRow, "commNm", ds_agreementVolumeResults.getCellData(i, "commNm"));
            ds_retrieveResult2.setCellData(newRow, "wageGoodsCd", ds_agreementVolumeResults.getCellData(i, "commCd"));
            ds_retrieveResult2.setCellData(newRow, "wageGoodsNm", ds_agreementVolumeResults.getCellData(i, "commNm"));

            ds_retrieveResult2.setCellData(newRow, "wrkQty", parseInt(arrQtyValue[j - 1]) * inputRate);
            ds_retrieveResult2.setCellData(newRow, "wrkWt", parseInt(arrWtValue[j - 1]) * inputRate);
            ds_retrieveResult2.setCellData(newRow, "unitWt", ds_agreementVolumeResults.getCellData(i, "unitWt"));
            ds_retrieveResult2.setCellData(newRow, "wrkCbm", parseInt(arrCbmValue[j - 1]) * inputRate);

            ds_retrieveResult2.setCellData(newRow, "wrkStpCd1", ds_agreementVolumeResults.getCellData(i, "sellItemCd")); // 0010 : 선측, 0006 : 선내
            ds_retrieveResult2.setCellData(newRow, "wageVolUnit", wageVolUnit);
            ds_retrieveResult2.setCellData(newRow, "wrkStDt", wrkStDt);
            ds_retrieveResult2.setCellData(newRow, "wrkStHh", wrkStHh);
            ds_retrieveResult2.setCellData(newRow, "wrkEndDt", wrkEndDt);
            ds_retrieveResult2.setCellData(newRow, "wrkEndHh", wrkEndHh);
            ds_retrieveResult2.setCellData(newRow, "wrkMthdCd", ds_agreementVolumeResults.getCellData(i, "wrkMthdCd"));

            // gr_retrieveResult2.setColumnDefaultValue("wrkWt", 'Edit') = 'NONE';//중량
            gr_retrieveResult2.setReadOnly("column", "wrkWt", true); //중량

            scwin.f_applyRTon(newRow);
        }
    }
};

/**
 * 협정물량의 잔여 수량 값에 대해   투입반월별로  1/n 처리한 후   그 결과 배열을  return 
 */
scwin.f_divideQTY = function (i) {
    let totalUnitQty        = 0;    // 전체 수량 .
    let divideUnitQty       = 0;    // 수량을 투입반원으로 나눈 값
    let divideRemainUnitQty = 0;    // 수량을 투입반원으로 나눈 후 남은 값
    let tmpQtyValue = new Array(scwin.cntLUnion);

    // 수량 - 협정물량의 수량은 KG 로 들어오므로, 실적 등록에서는 TON 단위로 처리해 줌.
    totalUnitQty        = ds_agreementVolumeResults.getCellData(i, "rmdrQty");
    divideUnitQty       = totalUnitQty / scwin.cntLUnion; // 투입반원으로 나눈 값
    divideRemainUnitQty = totalUnitQty % scwin.cntLUnion; // 투입반원으로 나누고 남은 값
    if (totalUnitQty == divideRemainUnitQty) {
        divideUnitQty = divideRemainUnitQty;
    }
    if (totalUnitQty == 0) {
        for (let j=0; j<scwin.cntLUnion; j++) {
            tmpQtyValue[j] = 0;
        }
        return tmpQtyValue;
    }

    if (scwin.cntLUnion == 1) {
        tmpQtyValue[0] = totalUnitQty;
        return tmpQtyValue;
    }

    // 나누어 줄 수가 더 많은 경우.
    if (scwin.cntLUnion <= totalUnitQty) {
        for (let j=0; j<scwin.cntLUnion; j++) {
            tmpQtyValue[j] = divideUnitQty;
            if (divideRemainUnitQty > 0) {
                tmpQtyValue[j]      = tmpQtyValue[j] + 1;
                divideRemainUnitQty = divideRemainUnitQty - 1;
            }
        }

    } else {
        // 투입반원으로 나눈 값
        divideUnitQty = totalUnitQty / totalUnitQty; 
        for (let j=0; j<scwin.cntLUnion; j++) {
            tmpQtyValue[j] = divideUnitQty;
            if (j >= totalUnitQty) {
                tmpQtyValue[j] = 0;
            }
        }
    }
    return tmpQtyValue;
};

/**
 * WT, CBM 값에 대해   투입반월별로  1/n 처리한 후   그 결과 배열을  return 
 * 단위 CBM 으로 처리하면서  필요가 없어짐..
 */
scwin.f_divideValue = function (pTotalValue) {
    let totalValue              = pTotalValue;  // 전체 값
    let divideUnitValue         = 0;            // 전체를 투입반원으로 나눈 값
    let divideRemainUnitValue   = 0;            // 전체를 투입반원으로 나눈 후 남은 값
    let arrResultValue = new Array(scwin.cntLUnion);

    if (pTotalValue == 0) {
        for (let j=0; j< scwin.cntLUnion; j++) {
            arrResultValue[j] = 0;
        }
        return arrResultValue;
    }

    if (scwin.cntLUnion == 1) {
        arrResultValue[0] = totalValue;

        return arrResultValue;
    }

    // 1/n 처리
    divideUnitValue = totalValue / scwin.cntLUnion; // 전체를 투입반원으로 나눈 값
    divideRemainUnitValue = totalValue - (divideUnitValue * scwin.cntLUnion); // CBM을 투입반원으로 나눈 후 남은 값
    //if(totalValue == divideRemainUnitValue ) divideUnitValue = divideRemainUnitValue ;

    // 나누어 줄 수가 더 많은 경우.
    if (scwin.cntLUnion <= totalValue) {
        for (let j=0; j < scwin.cntLUnion; j++) {
            arrResultValue[j] = divideUnitValue;
            if (divideRemainUnitValue > 0) {
                arrResultValue[j] = arrResultValue[j] + 1;
                divideRemainUnitValue = divideRemainUnitValue - 1;
            }
        }
    // 투입반원으로 나눈 값
    } else {
        divideUnitValue = totalValue / totalValue;
        for (let j=0; j < scwin.cntLUnion; j++) {
            arrResultValue[j] = divideUnitValue;
            if (j >= totalValue) arrResultValue[j] = 0;
        }
    }

    return arrResultValue;
};

/**
 * 노임물량 이 조건에 따라 달라짐 -  work by ChoiSeungEun , order by HongJungSuk
 * 1. 중량이나 CBM 값이 들어온 경우, 중량과 (CBM*0.883) 을 비교하여  큰 값으로  노임물량 set, 
 *    그리고, 작업장  코드가 '6W073' 인경우에는  위에서 계산된  노임 물량에 0.55를 적용
 *    중량과  CBM 값 모두 없는 경우, 입력된 노임 물량이 그대로 적용됨. 
 */
scwin.f_applyRTon = function (row) {
    let CBM_TARIFF = 0.883; /*CBM 적용 고정 비율 */

    let vWrkQty  = ds_retrieveResult2.getCellData(row, "wrkQty"); // 총수량
    let vWrkWt   = ds_retrieveResult2.getCellData(row, "wrkWt");  // 총중량
    let vUnitWt  = ds_retrieveResult2.getCellData(row, "unitWt"); // 단위 중량
    let vWrkCbm  = ds_retrieveResult2.getCellData(row, "wrkCbm"); // CBM
    let vWageVol = ds_retrieveResult2.getCellData(row, "wageVol");// 노임물량
    let vTempCBM = 0;

    if (vUnitWt == 0) vUnitWt = (vWrkWt / vWrkQty) == 0 ? 1 : (vWrkWt / vWrkQty);
    if (vWrkQty > 0) vWrkWt = vWrkQty * vUnitWt; // 수량 * 단위중량

    // 중량 ,CBM 모두 값이 있는 경우,
    if (vWrkWt > 0 && vWrkCbm > 0) {
        vTempCBM = vWrkCbm * CBM_TARIFF;
        if (vWrkWt > vTempCBM) {
            vWageVol = vWrkWt;
        }else {
            vWageVol = vTempCBM;
        }        

    //중량
    } else if (vWrkWt > 0) {
        vWageVol = vWrkWt; 

    //CBM
    } else if (vWrkCbm > 0) { 
        vWageVol = vWrkCbm;
        // 충남지사 요청사항으로 중량이 없고, CBM 이 업는 경우는 중량의 값은 (CBM*0.883 )이 된다.
        ds_retrieveResult2.setCellData(row, "wrkWt", ((vWrkCbm * CBM_TARIFF)));

    } else if (vWrkQty > 0) { 
        vWageVol = vWrkQty; 
    }

    ds_retrieveResult2.setCellData(row, "wageVol", parseInt(vWageVol));
};


