/**
 * 하역노임실적 데이터리스트 row 이동 시
 * ASIS : for=ds_retrieveResult2 event=OnColumnChanged(row,colid)
 */
scwin.ds_retrieveResult2_oncelldatachange = function (info) {
// console.log("scwin.ds_retrieveResult2_oncelldatachange 시작");
    let colId    = info.colID;
    let rowIndex = info.rowIndex;
    if (colId == "shiftClsCd") {
        scwin.f_ChangeShiftClsCd(rowIndex, colId);
    }

    //☏ TOBE 주석처리(중복적용되는 로직이 많아서)
    // if (colId == "lunionOrgCd") {
    //     scwin.f_commCdPopup(rowIndex, 3);
    // }

    if (colId == "reqClntNo") {
        for (let i=0; i<ds_retrieveResult3.getRowCount(); i++) {
            ds_retrieveResult3.setCellData(i, "reqClntNo", ds_retrieveResult2.getCellData(rowIndex, "reqClntNo"));
        }
    }
};


/**
 * 하역노임실적 그리드 셀 클릭
 * ASIS : for=gr_retrieveResult2 event=OnClick(row,colid)
 */
scwin.gr_retrieveResult2_oncellclick = function (rowIndex, columnIndex, columnId) {
// console.log("scwin.gr_retrieveResult2_oncellclick 시작 rowIndex : "+rowIndex);
    /* Start : 할증코드 리스트가 없는 경우 수정 막기 위해 */
    if (columnId == "chk") {
        scwin.isChecked = true;
        return;
    }

    scwin.f_setEditProtect(rowIndex);

    if ((columnId != "wageVol") && ds_retrieveResult3.getRowCount() > 0) {
        $c.win.alert("할증코드 리스트가 존재하는 경우에는 노임물량만 수정을 할 수 있습니다.");
        return;
    }

    // 반, HOLD_NO
    if (columnId == "lunionOrgCd" || columnId == "holdNo") {
        let cntMember = ds_retrieveResult2.getCellData(rowIndex, "cntUnionMember");
        if (cntMember > 0) {
            $c.win.alert("해당 노임편성내역을 먼저 삭제 한 후 반 정보를 수정할 수 있습니다.");
            return false;
        }
    } 

    if (columnId == "agrVolmgntNo") {
        scwin.isAgreementVolumeFilterClear        = true;
        scwin.ds_agreementVolumeResults_UseFilter = true;
        // ds_agreementVolumeResults.filter();
        scwin.ds_agreementVolumeResults_OnFilter();
    }
    /*--------------------:: End */ 
    scwin.f_wrkPlCdCheck(rowIndex, columnId);
};

/**
 * 하역노임실적 inputType이 textImage인 경우 이미지가 클릭됐을 때 발생
 * ASIS : for=gr_retrieveResult2 event=OnPopup(row,colid,data)
 */
scwin.gr_retrieveResult2_ontextimageclick = function (rowIndex, columnIndex) {
    let colId = gr_retrieveResult2.getColumnID(columnIndex);
    let data  = ds_retrieveResult2.getCellData(rowIndex, colId);
    if(colId == "reqClntNo") {
        scwin.f_openCommonPopUp(1, ds_retrieveResult2.getCellData(rowIndex, "reqClntNo"), "", "T", "T"); 
    }else {
    	scwin.f_OpenCommPopup(rowIndex, colId, data, "F");
    }
};

/**
 * 그리드 셀의 편집모드가 종료되어 포커스가 빠져나온 경우 이벤트 발생
 *  TOBE : inputType = textImage 인 것만 처리하기위해 사용(반[lunionOrgCd], 품명[commNm], 노임품목/품명[wageGoodsNm], 요청화주[reqClntNo])
 */
scwin.gr_retrieveResult2_onafteredit = function (rowIndex, columnIndex, value) {
    let colId = gr_retrieveResult2.getColumnID(columnIndex);
    if(colId == "lunionOrgCd"
    || colId == "commNm"
    || colId == "wageGoodsNm"
    ) {
        if(!$c.gus.cfIsNull(value) && value != scwin.oldValue) {
    	    scwin.f_OpenCommPopup(rowIndex, colId, value, "T");
        }else if($c.gus.cfIsNull(value)) {
            if(colId == "lunionOrgCd") {
                ds_retrieveResult2.setCellData(rowIndex, "chiefNm", "");
            }else if(colId == "commNm"){
                ds_retrieveResult2.setCellData(rowIndex, "commCd", "");
            }else if(colId == "wageGoodsNm") {
                ds_retrieveResult2.setCellData(rowIndex, "wageGoodsCd", "");
            }
        }
    }
    //수량[wrkQty], 중량[wrkWt], 단위중량[unitWt], CBM[wrkCbm], 노임물량[wageVol] 빈값으로 처리 시 0으로 초기값 주기
    // if(colId == "wrkQty"
    // || colId == "wrkWt"
    // || colId == "unitWt"
    // || colId == "wrkCbm"
    // || colId == "wageVol"
    // ) {
    //     if($c.gus.cfIsNull(value)) {
    //         ds_retrieveResult2.setCellData(rowIndex, colId, 0);
    //     }
    // }
};

/**
 * 입력이 가능한 컬럼에서 포커스가 빠져나가는 시점에 본 속성에 정의한 함수를 실행
 * 빈값인 경우 0으로 설정
 */
scwin.validatorNumber = function(val) {
    if($c.gus.cfIsNull(val)) {
        return "0";
    }
    return val;
};

/**
 * 하역노임실적 입력전 값
 * TOBE : scwin.oldValue 세팅 위해
 */
scwin.gr_retrieveResult2_onbeforeedit = function (rowIndex, columnIndex, value) {
//console.log("scwin.gr_retrieveResult2_onbeforeedit 입력전 값 : " + value);
    scwin.oldValue = value;
};

/**
 * 하역노임실적 그리드 편집모드 종료 이벤트
 * ASIS : for=gr_retrieveResult2 event=OnExit(row,colid,olddata)
 */
scwin.gr_retrieveResult2_oneditend = async function (rowIndex, columnIndex, value) {
    let colId    = gr_retrieveResult2.getColumnID(columnIndex);

    /**
     * TOBE if 조건 추가(if(colId != "commNm" && colId != "wageGoodsNm" && colId != "lunionOrgCd") 
     * scwin.gr_retrieveResult2_onafteredit 3건은 저기서 처리하기 위해
     **/
    if(colId != "commNm" && colId != "wageGoodsNm" && colId != "lunionOrgCd") {
        await scwin.f_AutoPopup(rowIndex, colId, scwin.oldValue, value);
    }

    if (scwin.lobranCd == "6AA" && (colId == "wrkQty" || colId == "wrkWt" || colId == "wrkCbm" || colId == "agrVolmgntNo")) {
        // 값이 변경된 경우에만 적용
        if (scwin.oldValue != value) {
            // 점소가 '부산'이고, 협정물량번호에 Event 가 발생한 경우   		 	      	
            if (scwin.lobranCd == "6AA" && colId == "agrVolmgntNo" && !$c.gus.cfIsNull(value)) {
                scwin.isAgreementVolumeFilterClear = false;
                // scwin.f_setAgreedVolumeData();
                await scwin.f_setAgreedVolumeData(rowIndex);
            }
            if (colId == "wrkWt") {
                ds_retrieveResult2.setCellData(rowIndex, "unitWt", 0);
            }
            scwin.f_applyRTon(rowIndex);
            //await scwin.f_setAgreedVolumeData(rowIndex);
        }

        let wageRsltsSeq = ds_retrieveResult2.getCellData(rowIndex, "wageRsltsSeq");
        if (!$c.gus.cfIsNull(wageRsltsSeq) && wageRsltsSeq > 0) {
            scwin.f_AutoLoad(2);
        }
    }
};


/**
 * 할증코드 필터처리
 * ASIS : for=ds_retrieveResult3 event=OnFilter(row)
 */
scwin.ds_retrieveResult3_OnFilter = function() {
// console.log("scwin.ds_retrieveResult3_OnFilter");
    if (!scwin.ds_retrieveResult3_UseFilter) {
        return;
    }
	let row = ds_retrieveResult2.getRowPosition();
// console.log("ds_retrieveResult2 gr_retrieveResult2.getFocusedRowIndex() : "+row + ", ds_retrieveResult2.getRowPosition() : "+ds_retrieveResult2.getRowPosition());
    let shift        = ds_retrieveResult2.getCellData(row, "shiftClsCd");   //Shift
    let hold         = ds_retrieveResult2.getCellData(row, "holdNo");       //H#
    let commCd       = ds_retrieveResult2.getCellData(row, "commCd");       //품목;코드
    let wrkStpCd1    = ds_retrieveResult2.getCellData(row, "wrkStpCd1");    //작업단계1
    let wrkStpCd2    = ds_retrieveResult2.getCellData(row, "wrkStpCd2");    //작업단계2
    let wrkStpCd3    = ds_retrieveResult2.getCellData(row, "wrkStpCd3");    //작업단계3
    let wrkStpCd4    = ds_retrieveResult2.getCellData(row, "wrkStpCd4");    //작업단계4
    let cvsslMgntNo  = ds_retrieveResult2.getCellData(row, "cvsslMgntNo");  //본선관리번호
    let wrkDt        = ds_retrieveResult2.getCellData(row, "wrkDt");        //시작일자
    //2006-04-29 2:48 추가
    let wrkMthdCd    = ds_retrieveResult2.getCellData(row, "wrkMthdCd");    //작업방법
    let lunionOrgCd  = ds_retrieveResult2.getCellData(row, "lunionOrgCd");  //반
    let wrkStHh      = ds_retrieveResult2.getCellData(row, "wrkStHh");      //시작시간
    let wrkEndDt     = ds_retrieveResult2.getCellData(row, "wrkEndDt");     //종료일자
    let wrkEndHh     = ds_retrieveResult2.getCellData(row, "wrkEndHh");     //종료시간
    let wageGoodsCd  = ds_retrieveResult2.getCellData(row, "wageGoodsCd");  //노임품목코드
    let wageVol      = ds_retrieveResult2.getCellData(row, "wageVol");      //노임물량
    let wageVolUnit  = ds_retrieveResult2.getCellData(row, "wageVolUnit");  //노임단위
    let wageRsltsSeq = ds_retrieveResult2.getCellData(row, "wageRsltsSeq"); //노임실적순번

    //모든 컬럼에 적용된 필터를 삭제
    ds_retrieveResult3.removeColumnFilterAll();

// console.log("scwin.ds_retrieveResult3_OnFilter()\n" +
// "holdNo == '"      + hold        + "'"
//         + " && shiftClsCd == '"  + shift       + "'"
//         + " && commCd == '"      + commCd      + "'"
//         + " && wrkStpCd1 == '"   + wrkStpCd1   + "'"
//         + " && wrkStpCd2 == '"   + wrkStpCd2   + "'"
//         + " && wrkStpCd3 == '"   + wrkStpCd3   + "'"
//         + " && wrkStpCd4 == '"   + wrkStpCd4   + "'"
//         + " && wrkMthdCd == '"   + wrkMthdCd   + "'"
//         + " && lunionOrgCd == '" + lunionOrgCd + "'"
//         + " && wrkStHh == '"     + wrkStHh     + "'"
//         + " && wrkEndDt == '"    + wrkEndDt    + "'"
//         + " && wrkEndHh == '"    + wrkEndHh    + "'"
//         + " && wageGoodsCd == '" + wageGoodsCd + "'"
//         + " && wageVol == '"     + wageVol     + "'"
//         + " && wageVolUnit == '" + wageVolUnit + "'"
//         + " && upperWageRsltsSeq == '" + wageRsltsSeq + "'"
//         + " && cvsslMgntNo == '" + cvsslMgntNo + "'"
//         + " && wrkDtNext == '"   + wrkDt       + "'"
// );

    $c.data.dataListFilter(ds_retrieveResult3, 
              "holdNo == '"      + hold        + "'"
        + " && shiftClsCd == '"  + shift       + "'"
        + " && commCd == '"      + commCd      + "'"
        + " && wrkStpCd1 == '"   + wrkStpCd1   + "'"
        + " && wrkStpCd2 == '"   + wrkStpCd2   + "'"
        + " && wrkStpCd3 == '"   + wrkStpCd3   + "'"
        + " && wrkStpCd4 == '"   + wrkStpCd4   + "'"
        + " && wrkMthdCd == '"   + wrkMthdCd   + "'"
        + " && lunionOrgCd == '" + lunionOrgCd + "'"
        + " && wrkStHh == '"     + wrkStHh     + "'"
        + " && wrkEndDt == '"    + wrkEndDt    + "'"
        + " && wrkEndHh == '"    + wrkEndHh    + "'"
        + " && wageGoodsCd == '" + wageGoodsCd + "'"
        + " && wageVol == '"     + wageVol     + "'"
        + " && wageVolUnit == '" + wageVolUnit + "'"
        + " && upperWageRsltsSeq == '" + wageRsltsSeq + "'"
        + " && cvsslMgntNo == '" + cvsslMgntNo + "'"
        + " && wrkDtNext == '"   + wrkDt       + "'"
    );
};

/**
 * 노조코드 필터처리
 * ASIS : for=ds_retrieveResult4 event=OnFilter(row)
 */
scwin.ds_retrieveResult4_OnFilter = function() {
// console.log("scwin.ds_retrieveResult4_OnFilter : "+ scwin.ds_retrieveResult4_UseFilter);
    if (!scwin.ds_retrieveResult4_UseFilter) {
        return;
    }
	let row   = ds_retrieveResult2.getRowPosition();
    let shift = ds_retrieveResult2.getCellData(row, "shiftClsCd");
// console.log("row : "+row + ", shift : "+shift);    
    //모든 컬럼에 적용된 필터를 삭제
    ds_retrieveResult4.removeColumnFilterAll();
    $c.data.dataListFilter(ds_retrieveResult4, "shiftClsCd == '" + shift + "'");
};

/**
 * 협정물량 필터처리
 * ASIS : for=ds_agreementVolumeResults event=OnFilter(row)
 */
scwin.ds_agreementVolumeResults_OnFilter = function() {
    if (!scwin.ds_agreementVolumeResults_UseFilter) {
        return;
    }
	let row   = ds_retrieveResult2.getRowPosition();
    let clsCd = acb_clsCd.getValue();
    let agrVolmgntNo = ds_retrieveResult2.getCellData(row, "agrVolmgntNo");
    //모든 컬럼에 적용된 필터를 삭제
    ds_agreementVolumeResults.removeColumnFilterAll();

    if (clsCd == "ALL" || $c.gus.cfIsNull(agrVolmgntNo) || scwin.isAgreementVolumeFilterClear) {
        return;
    }
    $c.data.dataListFilter(ds_agreementVolumeResults, "cntrBulkClsCd == '" + clsCd + "' && agrVolmgntNo == '" + agrVolmgntNo + "'");
};


